const fs = require('fs');
const path = require('path');
const dir = '分享回流/_tea_dsl';

function condition(name, op, values) {
  return {
    property_type: 'event_param',
    property_name: name,
    property_compose_type: 'origin',
    property_operation: op,
    property_values: Array.isArray(values) ? values : values === undefined ? [] : [values]
  };
}

function filter(...conds) {
  if (!conds.length) return [{ expression: { logic: 'and', expressions: [] } }];
  return [{ expression: { logic: 'and', expressions: conds.map(c => ({ logic: 'or', conditions: [c] })) } }];
}

function event(show_label, show_name, event_name, event_type, filters = []) {
  return { show_label, show_name, event_name, event_type, groups_v2: [], filters };
}

function dsl(queries) {
  return {
    use_app_cloud_id: true,
    periods: [
      {
        granularity: 'day',
        type: 'past_range',
        spans: [
          { type: 'past', past: { amount: 6, unit: 'day' } },
          { type: 'past', past: { amount: 0, unit: 'day' } }
        ],
        timezone: 'UTC',
        week_start: 1
      }
    ],
    version: 3,
    option: { region_filter: ['ROW'] },
    content: {
      query_type: 'funnel',
      profile_filters: [
        {
          show_name: '全体用户',
          show_label: '1',
          expression: { logic: 'and', expressions: [{ logic: 'or', conditions: [] }] }
        }
      ],
      page: { limit: 50, offset: 0 },
      option: {
        use_sample_data: false,
        refresh_cache: false,
        fusion: false,
        analysis_subject: {},
        is_parallel: true,
        statistics_mode: 0,
        add_window_period: true,
        window_period: 10,
        window_period_type: 'minute',
        window_type: 0,
        distribution_interval: 1,
        distribution_step: 0,
        distribution_unit: 'minute'
      },
      queries
    },
    resources: [{ project_ids: [55], subject_ids: [1], app_ids: [] }],
    app_ids: []
  };
}

const enter = event('1', 'PDP 进入', 'tiktokec_enter_product_detail', 'virtual', filter(condition('page_name', '=', 'product_detail')));
const show = event('2', '分享入口曝光', 'tiktokec_button_show', 'origin', filter(condition('button_name', '=', 'product_share')));
const click = event('3', '分享入口点击', 'tiktokec_button_click', 'origin', filter(condition('button_name', '=', 'product_share')));

const files = {
